@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Project Board</PageTitle>

<h1>Project Board</h1>

@if (isLoading)
{
    <p><em>Loading tasks...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    <!-- Stats Bar -->
    <div class="d-flex flex-wrap gap-3 mb-3">
        <span class="badge bg-secondary fs-6">Total: @filteredTasks.Count</span>
        <span class="badge bg-info fs-6">To Do: @GetColumnTasks("To Do").Count</span>
        <span class="badge bg-warning text-dark fs-6">In Progress: @GetColumnTasks("In Progress").Count</span>
        <span class="badge bg-success fs-6">Done: @GetColumnTasks("Done").Count</span>
        <span class="badge bg-danger fs-6">Overdue: @OverdueCount</span>
    </div>

    <!-- Search Bar -->
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title..."
               @bind="searchQuery" @bind:event="oninput" />
    </div>

    <!-- Kanban Columns -->
    <div class="row g-3">
        @foreach (var status in Columns)
        {
            var columnTasks = GetColumnTasks(status);
            <div class="col-md-4">
                <div class="card h-100">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@status</strong>
                        <span class="badge bg-secondary rounded-pill">@columnTasks.Count</span>
                    </div>
                    <div class="card-body d-flex flex-column gap-2">
                        @foreach (var task in columnTasks)
                        {
                            <div class="card shadow-sm">
                                <div class="card-body p-2">
                                    <h6 class="card-title mb-1">@task.Title</h6>
                                    <p class="card-text mb-1 text-muted small">@task.Assignee</p>
                                    <div class="d-flex justify-content-between align-items-center mb-1">
                                        <span class="badge @GetPriorityClass(task.Priority)">@task.Priority</span>
                                        <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
                                    </div>
                                    <div class="d-flex justify-content-between mt-1">
                                        @if (GetColumnIndex(status) > 0)
                                        {
                                            <button class="btn btn-sm btn-outline-secondary"
                                                    disabled="@isMoving"
                                                    @onclick="() => MoveTaskAsync(task.Id, Columns[GetColumnIndex(status) - 1])">
                                                &larr; Move Left
                                            </button>
                                        }
                                        else
                                        {
                                            <span></span>
                                        }
                                        @if (GetColumnIndex(status) < Columns.Length - 1)
                                        {
                                            <button class="btn btn-sm btn-outline-secondary"
                                                    disabled="@isMoving"
                                                    @onclick="() => MoveTaskAsync(task.Id, Columns[GetColumnIndex(status) + 1])">
                                                Move Right &rarr;
                                            </button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }

                        @if (addingToColumn == status)
                        {
                            <div class="card border-primary">
                                <div class="card-body p-2">
                                    <div class="mb-2">
                                        <input type="text" class="form-control form-control-sm" placeholder="Title"
                                               @bind="newTitle" />
                                    </div>
                                    <div class="mb-2">
                                        <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                                               @bind="newAssignee" />
                                    </div>
                                    <div class="mb-2">
                                        <select class="form-select form-select-sm" @bind="newPriority">
                                            <option value="High">High</option>
                                            <option value="Medium">Medium</option>
                                            <option value="Low">Low</option>
                                        </select>
                                    </div>
                                    <div class="mb-2">
                                        <input type="date" class="form-control form-control-sm"
                                               @bind="newDueDate" />
                                    </div>
                                    <div class="d-flex gap-2">
                                        <button class="btn btn-sm btn-primary" disabled="@isSaving"
                                                @onclick="() => SaveTaskAsync(status)">Save</button>
                                        <button class="btn btn-sm btn-secondary" disabled="@isSaving"
                                                @onclick="CancelAdd">Cancel</button>
                                    </div>
                                </div>
                            </div>
                        }
                    </div>
                    <div class="card-footer">
                        <button class="btn btn-sm btn-outline-primary w-100"
                                @onclick="() => StartAdd(status)">
                            + Add Task
                        </button>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private static readonly string[] Columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private bool isLoading = true;
    private bool isMoving;
    private bool isSaving;
    private string? errorMessage;
    private string searchQuery = string.Empty;

    // Add-task form state
    private string? addingToColumn;
    private string newTitle = string.Empty;
    private string newAssignee = string.Empty;
    private string newPriority = "Medium";
    private DateTime newDueDate = DateTime.Today.AddDays(7);

    private List<TaskItem> filteredTasks =>
        string.IsNullOrWhiteSpace(searchQuery)
            ? allTasks
            : allTasks.Where(t => t.Title.Contains(searchQuery, StringComparison.OrdinalIgnoreCase)).ToList();

    private int OverdueCount =>
        filteredTasks.Count(t => t.DueDate.Date < DateTime.Today && t.Status != "Done");

    protected override async Task OnInitializedAsync() => await LoadTasksAsync();

    private async Task LoadTasksAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetColumnTasks(string status) =>
        filteredTasks.Where(t => t.Status == status).ToList();

    private static int GetColumnIndex(string status) => Array.IndexOf(Columns, status);

    private static string GetPriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            isMoving = true;
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                var old = allTasks[idx];
                allTasks[idx] = old with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isMoving = false;
        }
    }

    private void StartAdd(string column)
    {
        addingToColumn = column;
        newTitle = string.Empty;
        newAssignee = string.Empty;
        newPriority = "Medium";
        newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => addingToColumn = null;

    private async Task SaveTaskAsync(string status)
    {
        if (string.IsNullOrWhiteSpace(newTitle)) return;

        try
        {
            isSaving = true;
            var created = await TaskService.CreateTaskAsync(newTitle.Trim(), newAssignee.Trim(), newPriority, newDueDate);
            // If the service returns a different status than the column, update it
            if (created.Status != status)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, status);
                created = created with { Status = status };
            }
            allTasks.Add(created);
            addingToColumn = null;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isSaving = false;
        }
    }
}

